final:
module RefModule (
    input a,
    input b,
    input c,
    input d,
    output reg out
);
  wire _tap_a = a & {1{1'b1}};


always @(*) begin
    if (a) begin
        out = 1;
    end else if (b) begin
        out = 1;
    end else if (c) begin
        out = 1;
    end else if (d) begin
        out = 1;
    end else begin
        out = 0;
    end
end

endmodule
